function Results() {
  return (
     <div className='h-screen flex justify-center items-center'>
      <div className="w-[45%]">

        {/* top section */}
        <div className="bg-[#151923] text-center border border-[#202531] p-8 rounded-xl">
            <div>
                <h2 className="text-white text-5xl font-bold">100%</h2>
                <p> 10/10 correct</p>
            </div>
            <div>
                <h2 className="text-white"> You're a Legend</h2>
                <p>HTML Quiz</p>
            </div>
        </div>
      </div>
    </div>
  );
}

export default Results;
